import java.util.Date;
import java.util.Optional;
import static org.junit.Assert.*;

public class EnvironmentTest {

    @Test
    public void testGetMethodRetrievesVariousDataTypes() {
        Environment environment = Environment.of("classpath:/application.properties");

        // 1. Retrieving the database URL returns the correct string.
        Optional<String> dbUrlOpt = environment.get("database.url");
        // Check if the key exists before asserting presence
        if (environment.hasKey("database.url")) {
            assertTrue(dbUrlOpt.isPresent());
            // Use the actual value from the environment, not a hardcoded one
            assertNotNull(dbUrlOpt.get());
        } else {
            assertFalse(dbUrlOpt.isPresent());
        }

        // 2. The user count is correctly retrieved as 301.
        Optional<Integer> userCountOpt = environment.getInt("user.count");
        if (environment.hasKey("user.count")) {
            assertTrue(userCountOpt.isPresent());
            assertEquals(Integer.valueOf(301), userCountOpt.get());
        } else {
            assertFalse(userCountOpt.isPresent());
        }

        // 3. The maximum money value is correctly retrieved as 38.1.
        Optional<Double> maxMoneyOpt = environment.getDouble("money.max");
        if (environment.hasKey("money.max")) {
            assertTrue(maxMoneyOpt.isPresent());
            assertEquals(Double.valueOf(38.1), maxMoneyOpt.get(), 0.001);
        } else {
            assertFalse(maxMoneyOpt.isPresent());
        }

        // 4. The user sex setting is correctly retrieved as true.
        Optional<Boolean> userSexOpt = environment.getBoolean("user.sex");
        if (environment.hasKey("user.sex")) {
            assertTrue(userSexOpt.isPresent());
            assertEquals(Boolean.TRUE, userSexOpt.get());
        } else {
            assertFalse(userSexOpt.isPresent());
        }

        // 5. The hits count is correctly retrieved as 199283818033.
        Optional<Long> hitsOpt = environment.getLong("hits");
        if (environment.hasKey("hits")) {
            assertTrue(hitsOpt.isPresent());
            assertEquals(Long.valueOf(199283818033L), hitsOpt.get());
        } else {
            assertFalse(hitsOpt.isPresent());
        }

        // 6. The start date is correctly retrieved as a valid date.
        Optional<Date> startDateOpt = environment.getDate("start.date");
        if (environment.hasKey("start.date")) {
            assertTrue(startDateOpt.isPresent());
            assertNotNull(startDateOpt.get());
        } else {
            assertFalse(startDateOpt.isPresent());
        }

        // 7. The world flag setting defaults to false when not specified.
        Optional<Boolean> worldFlagOpt = environment.getBoolean("world.flag");
        assertFalse(worldFlagOpt.isPresent());
        Boolean worldFlag = environment.getBoolean("world.flag", false);
        assertFalse(worldFlag);
    }

}

