import java.io.File;
import java.io.FileWriter;
import java.util.Map;

public class EnvironmentTest {

    @Test
    public void testGetPrefix() throws Exception {
        // Create a temporary properties file with the required content
        File propertiesFile = File.createTempFile("application", ".properties");
        propertiesFile.deleteOnExit();

        FileWriter writer = new FileWriter(propertiesFile);
        writer.write("app.version=0.0.2\n");
        writer.write("app.name=TestApp\n");
        writer.write("app.host=localhost\n");
        writer.write("app.port=8080\n");
        writer.write("app.debug=true\n");
        writer.write("app.path=/api\n");
        writer.write("app.mode=development\n");
        writer.close();

        // Initialize Environment using the created file
        Environment environment = Environment.of(propertiesFile);

        // Call the method under test
        Map<String, Object> result = environment.getPrefix("app");

        // Expected Result 1: The map contains exactly seven properties
        Assert.assertEquals(7, result.size());

        // Expected Result 2: The value for version in the returned map is 0.0.2
        Assert.assertEquals("0.0.2", result.get("version"));

        // Expected Result 3: The method correctly transforms property keys by removing the "app" prefix.
        // Verify that no key in the result map starts with "app"
        for (String key : result.keySet()) {
            Assert.assertFalse("Key should not start with 'app' prefix", key.startsWith("app"));
        }
    }

}

