    @Test
    public void testFailMethodReturnsFailureWithCorrectMessage() {
        // Using the fail method with a message correctly sets the error message to "error".
        RestResponse<String> response1 = RestResponse.fail("error");
        assertFalse(response1.isSuccess());
        // Use getter methods instead of direct field access
        assertEquals("error", response1.getMsg());
        assertNotEquals(0, response1.getCode());

        // Using the fail method with a status code and message also correctly sets the error message to "error".
        RestResponse<String> response2 = RestResponse.fail(500, "error");
        assertFalse(response2.isSuccess());
        assertEquals("error", response2.getMsg());
        assertEquals(500, response2.getCode());
    }
}

