public class DynamicContextTest {

    @Test
    public void testInitRecognizesJarContext() throws Exception {
        // Reset the static flag using reflection
        Field isJarContextField = DynamicContext.class.getDeclaredField("isJarContext");
        isJarContextField.setAccessible(true);
        isJarContextField.set(null, false);

        // First test with non-JAR context
        Class<?> nonJarClass = createMockClass("file:/some/path/to/classes/com/example/");
        DynamicContext.init(nonJarClass);
        Assert.assertFalse("Should not recognize JAR context initially", 
                          (Boolean) isJarContextField.get(null));

        // Now test with JAR context
        Class<?> jarClass = createMockClass("jar:file:/some/path/to/myapp.jar!/com/example/");
        DynamicContext.init(jarClass);

        // Verify that the environment is correctly recognized as a JAR context
        Assert.assertTrue("Should recognize JAR context when class is from a JAR", 
                         (Boolean) isJarContextField.get(null));
    }

    private Class<?> createMockClass(final String resourceUrl) throws Exception {
        return new Object() {
            public URL getResource(String name) throws Exception {
                return new URL(resourceUrl);
            }
        }.getClass();
    }

}

