        assertTrue(PatternKit.isImage(".PNG"));
        assertTrue(PatternKit.isImage(".jpg"));
        assertTrue(PatternKit.isImage(".Jpeg"));
        assertTrue(PatternKit.isImage(".gif"));
        assertTrue(PatternKit.isImage(".BMP"));
        assertTrue(PatternKit.isImage(".webp"));
        assertTrue(PatternKit.isImage(".jpeg"));

        // Test non-image file extensions
        assertFalse(PatternKit.isImage(".txt"));
        assertFalse(PatternKit.isImage(".pdf"));
        assertFalse(PatternKit.isImage(".docx"));
        assertFalse(PatternKit.isImage(".mp3"));

        // Test edge cases
        assertFalse(PatternKit.isImage("")); // Empty string
        assertFalse(PatternKit.isImage(null)); // Null input
